1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (count: number, wasAlive: boolean): boolean =>
12	  count === 3 || (count === 2 && wasAlive);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const alive = new Set(cells.map(keyOf));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	  for (const [x, y] of cells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const neighbor: Cell = [x + dx, y + dy];
20	      const key = keyOf(neighbor);
21	      const entry = neighborCounts.get(key) ?? { cell: neighbor, count: 0 };
22	      entry.count++;
23	      neighborCounts.set(key, entry);
24	    }
25	  }
26	  return [...neighborCounts]
27	    .filter(([key, { count }]) => survives(count, alive.has(key)))
28	    .map(([_, { cell }]) => cell);
29	}
30

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (both have only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should bring a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
26	    // L-shape: (0,1) (1,1) (0,0) — dead cell (1,0) has 3 live neighbors
27	    const input: [number, number][] = [[0, 1], [1, 1], [0, 0]];
28	    const result = nextGeneration(input);
29	    expect(result).toContainEqual([1, 0]);
30	  });
31	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
32	    // 3x3 filled square — center (1,1) has 8 live neighbors
33	    const input: [number, number][] = [
34	      [0, 0], [1, 0], [2, 0],
35	      [0, 1], [1, 1], [2, 1],
36	      [0, 2], [1, 2], [2, 2],
37	    ];
38	    const result = nextGeneration(input);
39	    expect(result).not.toContainEqual([1, 1]);
40	  });
41	  it("should handle negative coordinates", () => {
42	    // Vertical blinker shifted to negative region: cells at (-5,-5), (-5,-4), (-5,-3)
43	    const input: [number, number][] = [[-5, -5], [-5, -4], [-5, -3]];
44	    const expected: [number, number][] = [[-6, -4], [-5, -4], [-4, -4]];
45	    const result = nextGeneration(input);
46	    expect(result.sort()).toEqual(expected.sort());
47	  });
48	});
